const express = require('express');
const session = require('express-session');
const crypto = require('crypto');
const twilio = require('twilio');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

app.use(
  session({
    secret: process.env.SESSION_SECRET || 'replace-this-with-a-strong-secret',
    resave: false,
    saveUninitialized: false,
    cookie: {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      maxAge: 10 * 60 * 1000
    }
  })
);

const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID;
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN;
const TWILIO_FROM_NUMBER = process.env.TWILIO_FROM_NUMBER;

const twilioClient =
  TWILIO_ACCOUNT_SID && TWILIO_AUTH_TOKEN
    ? twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN)
    : null;

const OTP_TTL_MS = 5 * 60 * 1000;
const MAX_VERIFY_ATTEMPTS = 5;
const otpStore = new Map();

function generateOtp() {
  return String(crypto.randomInt(0, 1000000)).padStart(6, '0');
}

function setOtpForSession(sessionId, phoneNumber, code) {
  const expiresAt = Date.now() + OTP_TTL_MS;
  otpStore.set(sessionId, {
    phoneNumber,
    code,
    expiresAt,
    attempts: 0
  });
}

function getOtpForSession(sessionId) {
  const record = otpStore.get(sessionId);
  if (!record) return null;
  if (Date.now() > record.expiresAt) {
    otpStore.delete(sessionId);
    return null;
  }
  return record;
}

async function sendSms(to, message) {
  if (!twilioClient) {
    console.log(`[SMS MOCK] To: ${to} Message: ${message}`);
    return;
  }

  await twilioClient.messages.create({
    from: TWILIO_FROM_NUMBER,
    to,
    body: message
  });
}

function requireSession(req, res, next) {
  if (!req.session) {
    return res.status(500).json({ error: 'Session unavailable' });
  }
  next();
}

app.post('/auth/2fa/request', requireSession, async (req, res) => {
  try {
    const { phoneNumber } = req.body;

    if (!phoneNumber || typeof phoneNumber !== 'string') {
      return res.status(400).json({ error: 'phoneNumber is required' });
    }

    const code = generateOtp();
    setOtpForSession(req.sessionID, phoneNumber, code);

    await sendSms(
      phoneNumber,
      `Your verification code is ${code}. It expires in 5 minutes.`
    );

    req.session.pending2FA = true;
    req.session.twoFactorVerified = false;
    req.session.phoneNumber = phoneNumber;

    return res.json({ success: true, message: 'Verification code sent' });
  } catch (error) {
    return res.status(500).json({ error: 'Failed to send verification code' });
  }
});

app.post('/auth/2fa/verify', requireSession, (req, res) => {
  try {
    const { code } = req.body;

    if (!code || typeof code !== 'string') {
      return res.status(400).json({ error: 'code is required' });
    }

    const record = getOtpForSession(req.sessionID);

    if (!record) {
      return res.status(400).json({ error: 'Code expired or not found' });
    }

    if (req.session.phoneNumber && record.phoneNumber !== req.session.phoneNumber) {
      return res.status(400).json({ error: 'Phone number mismatch' });
    }

    record.attempts += 1;

    if (record.attempts > MAX_VERIFY_ATTEMPTS) {
      otpStore.delete(req.sessionID);
      req.session.pending2FA = false;
      req.session.twoFactorVerified = false;
      return res.status(429).json({ error: 'Too many attempts' });
    }

    if (record.code !== code.trim()) {
      return res.status(401).json({ error: 'Invalid code' });
    }

    otpStore.delete(req.sessionID);
    req.session.pending2FA = false;
    req.session.twoFactorVerified = true;
    req.session.authenticatedAt = Date.now();

    return res.json({ success: true, message: 'Two-factor authentication verified' });
  } catch (error) {
    return res.status(500).json({ error: 'Verification failed' });
  }
});

app.get('/auth/2fa/status', requireSession, (req, res) => {
  const record = getOtpForSession(req.sessionID);
  res.json({
    pending2FA: !!req.session.pending2FA,
    twoFactorVerified: !!req.session.twoFactorVerified,
    codeExpiresAt: record ? record.expiresAt : null
  });
});

function require2FA(req, res, next) {
  if (req.session && req.session.twoFactorVerified) {
    return next();
  }
  return res.status(403).json({ error: 'Two-factor authentication required' });
}

app.get('/protected', require2FA, (req, res) => {
  res.json({ success: true, message: 'Protected resource access granted' });
});

app.post('/logout', requireSession, (req, res) => {
  otpStore.delete(req.sessionID);
  req.session.destroy((err) => {
    if (err) return res.status(500).json({ error: 'Logout failed' });
    res.json({ success: true, message: 'Logged out' });
  });
});

